#!/usr/bin/env bash
# kaiju-zoo-submit.sh — submit one model's KAIJU1 encode via the generalized
# pipeline (cloudbuild-kaiju-encode.yaml), deriving all gate params from the
# model's qspec. Verifies the three real prerequisites are present first:
#   1. f16 truth on GCS      (models/<id>/<id>-f16.gguf) — fed by the IQ-ladder
#   2. imatrix on R2         (models/iq-ladder/<id>/<id>.imatrix) — IQ-ladder
#   3. base knot on R2       (models/<id>.knot) — the model's prior admission
#
# DRY-RUN BY DEFAULT. Pass --submit to actually fire. --writer-re <re> enables
# the v2 role-mix side-band for residual writers.
#
# Usage:
#   kaiju-zoo-submit.sh mistral-7b                 # dry-run (prints plan)
#   kaiju-zoo-submit.sh mistral-7b --submit        # fire the encode
#   kaiju-zoo-submit.sh mistral-7b --check         # prereq check only, exit
set -u

export PATH="/opt/homebrew/bin:/opt/homebrew/share/google-cloud-sdk/bin:/usr/bin:/bin:/usr/sbin:/sbin:${PATH:-}"
export CLOUDSDK_CONFIG="${CLOUDSDK_CONFIG:-/Users/buley/.config/gcloud}"
export CLOUDSDK_CORE_PROJECT="neutral-418500"

REPO="/Users/buley/Documents/Code/monorepo"
PROJECT="neutral-418500"
PROXY='https://edgework-web.taylorbuley.workers.dev/api/v1/r2/distributed-inference'
HELPER="$REPO/open-source/gnosis/distributed-inference/scripts/kaiju-gate-params.py"

MODEL="${1:-}"
[ -z "$MODEL" ] && { echo "usage: $0 <model-id> [--submit|--check] [--writer-re <re>]"; exit 2; }
shift || true

MODE="dry"       # dry | submit | check
WRITER_RE=""
while [ $# -gt 0 ]; do
  case "$1" in
    --submit) MODE="submit" ;;
    --check)  MODE="check" ;;
    --writer-re) shift; WRITER_RE="${1:-}" ;;
    *) echo "unknown arg: $1"; exit 2 ;;
  esac
  shift || true
done

log() { echo "[kaiju-zoo-submit $MODEL] $*"; }

# --- derive gate params from the qspec ------------------------------------
SUBST=$(python3 "$HELPER" --model-id "$MODEL" --format subst 2>/tmp/kzs.err)
if [ $? -ne 0 ] || [ -z "$SUBST" ]; then
  log "FAIL deriving gate params:"; cat /tmp/kzs.err >&2; exit 3
fi
# pull individual keys for the prereq check (json is easier)
JSON=$(python3 "$HELPER" --model-id "$MODEL" --format json)
F16_GCS=$(printf '%s' "$JSON" | python3 -c 'import json,sys;print(json.load(sys.stdin)["_F16_GCS"])')
IMATRIX_KEY=$(printf '%s' "$JSON" | python3 -c 'import json,sys;print(json.load(sys.stdin)["_IMATRIX_KEY"])')
BASE_KNOT_KEY=$(printf '%s' "$JSON" | python3 -c 'import json,sys;print(json.load(sys.stdin)["_BASE_KNOT_KEY"])')
OUT_KEY=$(printf '%s' "$JSON" | python3 -c 'import json,sys;print(json.load(sys.stdin)["_OUT_KEY"])')

# --- prerequisite presence ------------------------------------------------
r2_present() { # key -> 0 if 200/206
  local code
  code=$(timeout 30 curl -s -o /dev/null -w '%{http_code}' -r 0-15 \
           -H 'User-Agent: Mozilla/5.0' "$PROXY/$1" </dev/null 2>/dev/null)
  [ "$code" = "200" ] || [ "$code" = "206" ]
}
gcs_present() { timeout 40 gsutil -q stat "$1" </dev/null 2>/dev/null; }

log "prerequisite check:"
OK=1
if gcs_present "$F16_GCS"; then echo "   [ok]  f16     $F16_GCS"; else echo "   [MISS] f16     $F16_GCS  (run IQ-ladder for $MODEL)"; OK=0; fi
if r2_present "$IMATRIX_KEY"; then echo "   [ok]  imatrix $IMATRIX_KEY"; else echo "   [MISS] imatrix $IMATRIX_KEY  (run IQ-ladder for $MODEL)"; OK=0; fi
if r2_present "$BASE_KNOT_KEY"; then echo "   [ok]  base    $BASE_KNOT_KEY"; else echo "   [MISS] base    $BASE_KNOT_KEY  (needs a prior admitted knot)"; OK=0; fi
if r2_present "$OUT_KEY"; then echo "   [note] output $OUT_KEY already exists (will overwrite on ship)"; fi

if [ "$OK" -ne 1 ]; then
  log "NOT READY — prerequisites missing (see above). Feed via the IQ-ladder first."
  [ "$MODE" = "check" ] && exit 1
  exit 1
fi
log "READY — all prerequisites present."
[ "$MODE" = "check" ] && exit 0

# --- assemble + fire ------------------------------------------------------
EXTRA=""
[ -n "$WRITER_RE" ] && EXTRA=";_WRITER_RE=$WRITER_RE"
FULL_SUBST="${SUBST}${EXTRA}"

CMD=(gcloud builds submit --config=cloudbuild-kaiju-encode.yaml
     "--substitutions=${FULL_SUBST}" --project="$PROJECT" --async --quiet .)

if [ "$MODE" = "dry" ]; then
  log "DRY-RUN — would submit:"
  printf '   cd %s && \\\n   %s\n' "$REPO" "${CMD[*]}"
  exit 0
fi

# one-encode-at-a-time guard: refuse if any ladder/kaiju encode is ongoing.
# NB: include _OUT_KEY — a KAIJU encode may carry only _OUT_KEY (models/<id>-kaiju*.knot)
# and no _HF_SOURCE/_KNOT_NAME (e.g. the role-mix kaiju2 build), so keying on
# _HF_SOURCE/_KNOT_NAME alone goes blind to it. `\.knot` catches any knot-producing
# encode; the slash pattern catches ladders (_HF_SOURCE org/repo).
ONGOING=$(timeout 90 gcloud builds list --project "$PROJECT" --ongoing \
            --format='value(id,substitutions._HF_SOURCE,substitutions._KNOT_NAME,substitutions._OUT_KEY)' </dev/null 2>/dev/null)
if printf '%s\n' "$ONGOING" | grep -qE '[[:alnum:]_.-]+/[[:alnum:]_.-]+|kaiju|\.knot'; then
  log "REFUSE — an encode is already in flight (one-at-a-time):"
  printf '%s\n' "$ONGOING" | sed 's/^/    /'
  exit 4
fi

cd "$REPO" || exit 5
log "submitting KAIJU encode for $MODEL ..."
"${CMD[@]}"
